#![no_main]
//! CSCI vProg guest for `PrivateVickreyAuction` — generated by portrait-atelier (M3).
//! new_state_hash is computed over the NEW state derived from the portrait body
//! Return expression; entrypoint requires(...) are asserted in-guest.
//! Fields not referenced by the return expr are carried forward unchanged.
//! Journal: covenant_id[32] || new_state_hash[32] || rule_hash[32] || seq[8 LE]
risc0_zkvm::guest::entry!(main);

use risc0_zkvm::guest::env;
use sha2::{Digest, Sha256};

/// Auto-derived KovId: sha256(silverc compiled script bytes).
const COV_ID: [u8; 32] = [0x40, 0x2a, 0xa3, 0x16, 0xf6, 0x5d, 0x94, 0x40, 0x77, 0x5f, 0x3a, 0x9f, 0xed, 0xcf, 0x02, 0x3b, 0x89, 0x23, 0xf7, 0x03, 0xf1, 0x35, 0x5a, 0x27, 0x3f, 0x51, 0x2f, 0x6d, 0x01, 0x1e, 0x1a, 0x06];

fn sha256_bytes(data: &[u8]) -> [u8; 32] {
    let mut h = Sha256::new();
    h.update(data);
    h.finalize().into()
}

fn encode_state(auctioneer: [u8; 32], bids_root: [u8; 32], commitment: [u8; 32], winner: [u8; 32], clearing_price: i64, seq: i64) -> Vec<u8> {
    let mut out: Vec<u8> = Vec::new();
    out.extend_from_slice(&auctioneer);
    out.extend_from_slice(&bids_root);
    out.extend_from_slice(&commitment);
    out.extend_from_slice(&winner);
    out.extend_from_slice(&clearing_price.to_le_bytes());
    out.extend_from_slice(&seq.to_le_bytes());
    out
}

/// Verify the `clearing_rule` VProg transition and return the 104-byte CSCI journal.
fn verify_clearing_rule(covenant_id: [u8; 32], prev_seq: u64, auctioneer: [u8; 32], bids_root: [u8; 32], commitment: [u8; 32], winner: [u8; 32], clearing_price: i64, seq: i64) -> [u8; 104] {
    // ---------------------------------------------------------------------
    // INPUTS (typed):
    //   covenant_id: [u8; 32]   — KovId of the covenant this proof binds to
    //   prev_seq:    u64        — sequence of the prev on-chain state
    //   auctioneer: [u8; 32]   — prev state field (carried from main env::read)
    //   bids_root: [u8; 32]   — prev state field (carried from main env::read)
    //   commitment: [u8; 32]   — prev state field (carried from main env::read)
    //   winner: [u8; 32]   — prev state field (carried from main env::read)
    //   clearing_price: i64   — prev state field (carried from main env::read)
    //   seq: i64   — prev state field (carried from main env::read)
    //   next_commitment: [u8; 32]   — transition arg (env::read below)
    //   next_winner: [u8; 32]   — transition arg (env::read below)
    //   next_clearing_price: i64   — transition arg (env::read below)
    // JOURNAL (104 bytes, committed at the end):
    //   [0..32)   covenant_id
    //   [32..64)  new_state_hash = sha256(encode_state(NEW fields))
    //   [64..96)  rule_hash      = sha256(entry-point name)
    //   [96..104) seq (u64 LE)   = prev_seq + 1
    // ---------------------------------------------------------------------
    let next_commitment: [u8; 32] = env::read();
    let next_winner: [u8; 32] = env::read();
    let next_clearing_price: i64 = env::read();
    // ===== DEVELOPER PREDICATE HOOK (author the heavy proof logic here) =====
    #[allow(unused_variables, clippy::too_many_arguments)]
    fn predicate(auctioneer: [u8; 32], bids_root: [u8; 32], commitment: [u8; 32], winner: [u8; 32], clearing_price: i64, seq: i64, next_commitment: [u8; 32], next_winner: [u8; 32], next_clearing_price: i64) -> bool {
        // TODO: author the heavy off-chain claim over the typed inputs above
        // (fold / Pedersen open / Merkle membership / policy circuit). Returns true
        // by default — the guest does NOT yet prove this claim.
        true
    }
    assert!(predicate(auctioneer, bids_root, commitment, winner, clearing_price, seq, next_commitment, next_winner, next_clearing_price), "vprog predicate failed");
    // ===== END DEVELOPER PREDICATE HOOK =====
    let new_commitment = next_commitment;
    let new_winner = next_winner;
    let new_clearing_price = next_clearing_price;
    let new_seq = seq + 1;
    let new_state_bytes = encode_state(auctioneer, bids_root, new_commitment, new_winner, new_clearing_price, new_seq);
    let journal_state_hash = sha256_bytes(&new_state_bytes);
    let rule_hash = sha256_bytes(b"clearing_rule"); // rule = entry point name
    let journal_seq = prev_seq.checked_add(1).expect("seq overflow");

    let mut journal = [0u8; 104];
    journal[..32].copy_from_slice(&covenant_id);
    journal[32..64].copy_from_slice(&journal_state_hash);
    journal[64..96].copy_from_slice(&rule_hash);
    journal[96..].copy_from_slice(&journal_seq.to_le_bytes());
    journal
}

fn main() {
    let covenant_id = COV_ID; // auto-derived KovId
    let prev_seq: u64 = env::read();
    let auctioneer: [u8; 32] = env::read();
    let bids_root: [u8; 32] = env::read();
    let commitment: [u8; 32] = env::read();
    let winner: [u8; 32] = env::read();
    let clearing_price: i64 = env::read();
    let seq: i64 = env::read();
    let journal = verify_clearing_rule(covenant_id, prev_seq, auctioneer, bids_root, commitment, winner, clearing_price, seq);
    env::commit_slice(&journal);
}
